import{_ as o,o as t,c as r,ak as d}from"./chunks/framework.BbJJwCwT.js";const h=JSON.parse('{"title":"Repository Map","description":"Quick path through the repo for contributors and power users.","frontmatter":{"title":"Repository Map","description":"Quick path through the repo for contributors and power users.","editLink":true,"foreBlocksVersion":"0.1.34"},"headers":[],"relativePath":"reference/repository-map.md","filePath":"reference/repository-map.md"}'),a={name:"reference/repository-map.md"};function c(s,e,l,n,i,b){return t(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="repository-map" tabindex="-1">Repository Map <a class="header-anchor" href="#repository-map" aria-label="Permalink to “Repository Map”">​</a></h1><p>This page gives a quick path through the repository for contributors and power users.</p><h2 id="top-level-areas" tabindex="-1">Top-level areas <a class="header-anchor" href="#top-level-areas" aria-label="Permalink to “Top-level areas”">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="https://github.com/lseman/foreblocks/blob/main/README" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>GitHub landing page</td></tr><tr><td><a href="https://github.com/lseman/foreblocks/blob/main/docs/.vitepress/config.js" target="_blank" rel="noreferrer"><code>docs/.vitepress/config.js</code></a></td><td>Navigation and site structure for the <code>/docs/</code> site</td></tr><tr><td><code>web/</code></td><td>Static landing page assets for the published site root</td></tr><tr><td><code>docs/</code></td><td>VitePress source for the versioned documentation site</td></tr><tr><td><code>examples/</code></td><td>Notebooks and runnable examples</td></tr><tr><td><code>foreblocks/</code></td><td>Main forecasting library</td></tr><tr><td><code>foretools/</code></td><td>Companion tooling</td></tr><tr><td><code>darts/</code></td><td>Neural architecture search (DARTS)</td></tr></tbody></table><h2 id="foreblocks" tabindex="-1"><code>foreblocks/</code> <a class="header-anchor" href="#foreblocks" aria-label="Permalink to “foreblocks/”">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="https://github.com/lseman/foreblocks/blob/main/foreblocks/__init__.py" target="_blank" rel="noreferrer"><code>foreblocks/__init__.py</code></a></td><td>Top-level public exports</td></tr><tr><td><a href="https://github.com/lseman/foreblocks/blob/main/foreblocks/config.py" target="_blank" rel="noreferrer"><code>foreblocks/config.py</code></a></td><td>Public configuration dataclasses (<code>ModelConfig</code>, <code>TrainingConfig</code>)</td></tr><tr><td><code>foreblocks/ops/</code></td><td>Low-level compute kernels (Triton/CUDA): <code>kernels/</code> (grouped_gemm, swiglu, norms), <code>attention/</code> (FLA, fused RoPE, paged/chunked), <code>mamba/</code> (SSD, conv1d), <code>raven/</code></td></tr><tr><td><code>foreblocks/layers/</code></td><td>Reusable <code>nn.Module</code> primitives: <code>norms/</code>, <code>embeddings/</code>, <code>graph/</code></td></tr><tr><td><code>foreblocks/modules/</code></td><td>Composable model modules: <code>attention/</code>, <code>moe/</code>, <code>blocks/</code>, <code>heads/</code>, <code>skip/</code></td></tr><tr><td><code>foreblocks/models/</code></td><td>Assembled models + composition APIs (<code>ForecastingModel</code>, <code>GraphForecastingModel</code>), <code>popular/</code> named models, <code>transformer/</code> stack, <code>kan/</code> (Kolmogorov-Arnold backbone)</td></tr><tr><td><code>foreblocks/sequence/</code></td><td>Alternative sequence backbones: <code>mamba/</code> (original), <code>mamba_hybrid/</code> (formerly <code>custom_mamba</code>), <code>raven/</code> (formerly <code>custom_raven</code>)</td></tr><tr><td><code>foreblocks/core/</code></td><td>Core forecasting internals (<code>model</code>, <code>att</code>, <code>sampling</code>, <code>extend</code>), plus <code>training/</code> (trainer) and <code>evaluation/</code> (metrics)</td></tr><tr><td><code>foreblocks/data/</code></td><td>Dataset and dataloader helpers</td></tr><tr><td><code>foreblocks/ts_handler/</code></td><td>Preprocessing and sequence construction</td></tr><tr><td><code>foreblocks/mltracker/</code></td><td>Experiment tracking</td></tr><tr><td><code>foreblocks/experimental/</code></td><td>Not-yet-stable components: <code>attention_kernels/</code> (formerly <code>custom_att</code>, has own <code>setup.py</code>)</td></tr><tr><td><code>foreblocks/third_party/</code></td><td>Small vendored compatibility helpers; larger external projects should stay outside the wheel</td></tr></tbody></table><h2 id="package-organization-post-reorg" tabindex="-1">Package organization (post-reorg) <a class="header-anchor" href="#package-organization-post-reorg" aria-label="Permalink to “Package organization (post-reorg)”">​</a></h2><p>The package was reorganized into a tiered layout. There are <strong>no compatibility shims</strong> — old import paths (<code>foreblocks.transformer.*</code>, <code>foreblocks.blocks.*</code>, <code>foreblocks.custom_mamba.*</code>, <code>foreblocks.custom_raven.*</code>, <code>foreblocks.custom_att.*</code>) were hard-renamed. See <a href="./reorg-migration.html">Reorg Migration Map</a> for the full old → new table.</p><table tabindex="0"><thead><tr><th>Tier</th><th>Package</th><th>What lives here</th></tr></thead><tbody><tr><td>compute</td><td><code>foreblocks/ops/</code></td><td>Triton/CUDA kernels, no <code>nn.Module</code> API surface</td></tr><tr><td>primitives</td><td><code>foreblocks/layers/</code></td><td>Reusable <code>nn.Module</code> primitives (norms, embeddings, graph)</td></tr><tr><td>modules</td><td><code>foreblocks/modules/</code></td><td>Composable model modules (attention, moe, blocks, heads, skip)</td></tr><tr><td>models</td><td><code>foreblocks/models/</code></td><td>Fully assembled models + composition, incl. <code>popular/</code> and <code>transformer/</code></td></tr><tr><td>backbones</td><td><code>foreblocks/sequence/</code></td><td>Alternative sequence backbones (mamba, mamba_hybrid, raven)</td></tr><tr><td>experimental</td><td><code>foreblocks/experimental/</code></td><td>Not-yet-stable sub-projects (e.g. attention_kernels)</td></tr></tbody></table><p>Conventions:</p><ul><li><code>ops/</code> is pure compute. If it imports <code>torch.nn</code> as an API surface, it belongs in <code>layers/</code> or <code>modules/</code>.</li><li><code>modules/blocks/</code> holds research blocks; <code>models/popular/</code> holds the named end-to-end models (NBEATS, Informer, …). The <code>transformer/popular/</code> and <code>blocks/popular/</code> split was merged into <code>models/popular/</code>.</li><li><code>sequence/</code> drops the old <code>custom_</code> prefix; <code>custom_mamba</code> → <code>mamba_hybrid</code> to distinguish it from the original <code>mamba</code>.</li><li>Frontend assets under <code>foreblocks/studio/</code> and <code>foreblocks/mltracker/dashboard_v2/</code>: package only built <code>dist</code> assets; keep <code>node_modules</code>, runtime databases, and local tracker artifacts out of git and release archives.</li><li><code>mltracker/mltracker_data/</code>: prefer <code>.foreblocks/mltracker_data</code>, <code>~/.foreblocks/mltracker_data</code>, or an explicit user-configured run directory rather than the package tree.</li></ul><h2 id="foretools" tabindex="-1"><code>foretools/</code> <a class="header-anchor" href="#foretools" aria-label="Permalink to “foretools/”">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>foretools/tsgen/</code></td><td>Synthetic time-series generation</td></tr><tr><td><code>foretools/bohb/</code></td><td>BOHB, TPE configuration, pruning, and optimization plots</td></tr><tr><td><code>foretools/foreminer/</code></td><td>Exploratory analysis and diagnostics</td></tr><tr><td><code>foretools/fengineer/</code></td><td>Feature engineering utilities</td></tr><tr><td><code>foretools/emd_like/</code></td><td>Decomposition tools</td></tr><tr><td><code>foretools/tsaug/</code></td><td>AutoDA-Timeseries: automated data augmentation with adaptive policy</td></tr></tbody></table><h2 id="recommended-entry-points-by-task" tabindex="-1">Recommended entry points by task <a class="header-anchor" href="#recommended-entry-points-by-task" aria-label="Permalink to “Recommended entry points by task”">​</a></h2><table tabindex="0"><thead><tr><th>Task</th><th>Entry point</th></tr></thead><tbody><tr><td>Training a baseline model</td><td><a href="https://github.com/lseman/foreblocks/blob/main/README" target="_blank" rel="noreferrer"><code>README.md</code></a>, <a href="./../getting-started.html">Getting Started</a></td></tr><tr><td>Understanding architecture composition</td><td><a href="https://github.com/lseman/foreblocks/tree/main/foreblocks/models" target="_blank" rel="noreferrer"><code>foreblocks/models/</code></a></td></tr><tr><td>Working with graph forecasting</td><td><a href="https://github.com/lseman/foreblocks/blob/main/foreblocks/models/graph_forecasting.py" target="_blank" rel="noreferrer"><code>foreblocks/models/graph_forecasting.py</code></a>, <a href="https://github.com/lseman/foreblocks/tree/main/foreblocks/layers/graph" target="_blank" rel="noreferrer"><code>foreblocks/layers/graph/</code></a></td></tr><tr><td>Writing Triton kernels</td><td><a href="https://github.com/lseman/foreblocks/tree/main/foreblocks/ops" target="_blank" rel="noreferrer"><code>foreblocks/ops/</code></a></td></tr><tr><td>Configuring runs</td><td><a href="https://github.com/lseman/foreblocks/blob/main/foreblocks/config.py" target="_blank" rel="noreferrer"><code>foreblocks/config.py</code></a></td></tr><tr><td>Building dataloaders</td><td><a href="https://github.com/lseman/foreblocks/blob/main/foreblocks/data/dataset.py" target="_blank" rel="noreferrer"><code>foreblocks/data/dataset.py</code></a></td></tr><tr><td>Adding preprocessing logic</td><td><a href="https://github.com/lseman/foreblocks/blob/main/foreblocks/ts_handler/preprocessing.py" target="_blank" rel="noreferrer"><code>foreblocks/ts_handler/preprocessing.py</code></a></td></tr><tr><td>Exploring transformer internals</td><td><a href="https://github.com/lseman/foreblocks/blob/main/foreblocks/models/transformer/transformer.py" target="_blank" rel="noreferrer"><code>foreblocks/models/transformer/transformer.py</code></a></td></tr><tr><td>Working on architecture search</td><td><a href="https://github.com/lseman/foreblocks/tree/main/darts" target="_blank" rel="noreferrer"><code>darts/</code></a></td></tr><tr><td>Using SSM / Mamba-style blocks</td><td><a href="https://github.com/lseman/foreblocks/tree/main/foreblocks/sequence/mamba_hybrid" target="_blank" rel="noreferrer"><code>foreblocks/sequence/mamba_hybrid/</code></a></td></tr><tr><td>Generating synthetic data</td><td><a href="https://github.com/lseman/foreblocks/tree/main/foretools/tsgen" target="_blank" rel="noreferrer"><code>foretools/tsgen/</code></a></td></tr><tr><td>Running hyperparameter search</td><td><a href="https://github.com/lseman/foreblocks/tree/main/foretools/bohb" target="_blank" rel="noreferrer"><code>foretools/bohb/</code></a></td></tr><tr><td>Augmenting training data adaptively</td><td><a href="https://github.com/lseman/foreblocks/tree/main/foretools/tsaug" target="_blank" rel="noreferrer"><code>foretools/tsaug/</code></a></td></tr></tbody></table><h2 id="related-pages" tabindex="-1">Related pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to “Related pages”">​</a></h2><ul><li><a href="./../architecture/system-overview.html">System Overview</a></li><li><a href="./public-api.html">Public API</a></li><li><a href="./../foretools/index.html">Foretools Overview</a></li><li><a href="./../contributing/docs-workflow.html">Documentation Workflow</a></li></ul>',17)])])}const p=o(a,[["render",c]]);export{h as __pageData,p as default};
